# ШАБЛОН 4: Декораторы для логирования и проверки
# Экспериментируй: создай свои декораторы, комбинируй их!

import random

# Декоратор логирования
def log_call(func):
    def wrapper(*args, **kwargs):
        print(f'[LOG] Вызов {func.__name__}')
        result = func(*args, **kwargs)
        print(f'[LOG] {func.__name__} завершена -> {result}')
        return result
    return wrapper

# Декоратор проверки результата
def validate_positive(func):
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        if result is not None and result < 0:
            print('[WARN] Отрицательный результат!')
            return None
        return result
    return wrapper

# Применяем оба декоратора
@log_call
@validate_positive
def calculate(a, b, operation):
    if operation == '+':
        return a + b
    elif operation == '-':
        return a - b
    elif operation == '*':
        return a * b
    elif operation == '/':
        return a / b if b != 0 else None
    return None

print('=== ДЕКОРАТОРЫ В ДЕЙСТВИИ ===')
print('5 + 3 =', calculate(5, 3, '+'))
print('3 - 10 =', calculate(3, 10, '-'))  # отрицательный!
