# TEMPLATE 4: Decorators for logging and validation
# Experiment: create your own decorators, combine them!

import random

# Logging decorator
def log_call(func):
    def wrapper(*args, **kwargs):
        print(f'[LOG] Calling {func.__name__}')
        result = func(*args, **kwargs)
        print(f'[LOG] {func.__name__} finished -> {result}')
        return result
    return wrapper

# Validation decorator
def validate_positive(func):
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        if result is not None and result < 0:
            print('[WARN] Negative result!')
            return None
        return result
    return wrapper

# Apply both decorators
@log_call
@validate_positive
def calculate(a, b, operation):
    if operation == '+':
        return a + b
    elif operation == '-':
        return a - b
    elif operation == '*':
        return a * b
    elif operation == '/':
        return a / b if b != 0 else None
    return None

print('=== DECORATORS IN ACTION ===')
print('5 + 3 =', calculate(5, 3, '+'))
print('3 - 10 =', calculate(3, 10, '-'))  # negative!
print('7 * 4 =', calculate(7, 4, '*'))

# Decorator with parameter for timing
import time

def timeit(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        elapsed = time.time() - start
        print(f'[TIME] {func.__name__} took {elapsed:.4f} sec')
        return result
    return wrapper

@timeit
def slow_sum(n):
    return sum(range(n))

print('\nsum(1000000):')
s = slow_sum(1000000)
print('Sum:', s)
